const date = $now.setZone('America/New_York').minus({ days: 1 }).toFormat('yyyy-LL-dd');
return [{ json: {
  episode_date: date,
  insights_url: `https://aidailybrief.ai/e/${date}.md`,
  transcript_url: `https://aidailybrief.ai/e/${date}/transcript.md`,
  episode_url: `https://aidailybrief.ai/e/${date}`,
} }];

