={{ JSON.stringify({
  model: "claude-sonnet-5",
  thinking: { type: "disabled" },
  max_tokens: 16000,
  system: [{ type: "text", text: "You synthesize ONE cohesive, publish-ready content idea from a full episode of The AI Daily Brief (host: Nathaniel 'NLW' Whittemore) for Alec Foster, Chief AI Architect & Responsible AI Lead at Marketing + Media Alliance (MMA). Alec's lane (score relevance to this): Claude/Anthropic, Claude Code and agent SDKs, agentic AI, AI governance, responsible AI, AI safety, marketing AI, enterprise AI adoption, MCP, prompt engineering, LLM evals, AI strategy for CMOs. You are given BOTH the show's own curated insights/numbers AND the full transcript. Your job is NOT to list separate topics. Find the single strongest through-line of the WHOLE episode and build one post around it, weaving in the 2-4 most important supporting threads with their specific numbers, names, and quotes.", cache_control: { type: "ephemeral" } }],
  messages: [{ role: "user", content:
    "Synthesize THIS ENTIRE AI Daily Brief episode into ONE content idea. Return ONLY JSON with this shape: {\"episode_title\":\"the episode's real title\",\"episode_summary\":\"3-5 sentences\",\"idea\":{\"topic_headline\":\"single-post headline capturing the episode's core tension\",\"hook\":\"2-3 sentences\",\"key_points\":[\"5-9 bullets, the supporting threads woven together, each >=15 words with a concrete number/name/quote\"],\"observations\":[\"2-5 bullets of nuance or counterpoints\"],\"tips\":[\"0-5 actionable takeaways\"],\"quotes\":[{\"speaker\":\"\",\"quote\":\">=10 words verbatim\",\"timestamp\":\"\"}],\"why_it_matters\":\"3-5 sentences, Alec/MMA angle\",\"open_question\":\"1 sentence\",\"draft_angle\":\"1-2 sentence spine that UNIFIES the whole post\",\"further_reading\":[{\"title\":\"\",\"url\":\"\"}],\"topics\":[\"subset of Claude|Agents|AI Governance|Marketing AI|Measurement|AI Strategy|LLMs|MCP|Voice AI|AI Safety|Enterprise AI|Creator Economy|Policy|Research|Content|Prompt Engineering|Reddit/Search|OpenAI|Anthropic|Google|Meta|Codex\"],\"audience\":[\"subset of Marketers|AI Practitioners|Execs/CMOs|Governance|Builders|General\"],\"hot_take_potential\":\"High|Medium|Low\",\"utility\":\"High|Medium|Low\",\"relevance\":\"High|Medium|Low\",\"format\":\"Hot Take|Explainer|Framework|Case Study|Announcement\"}}. For quotes: when the host quotes a NAMED third party (person, paper, company), keep it accurate and verbatim so it is citable; the host's OWN words may be cleaned of filler, false starts, and transcription artifacts (never reproduce 'um'/'uh'). Prefer NLW's sharpest framing and cited stats; attribute cited third parties. Ignore sponsor reads and intros/outros. Use the show's insights for hard numbers and the transcript for nuance and quotes.\n\n" +
    "Episode date: " + $('Build Episode URLs').item.json.episode_date + "\nEpisode URL: " + $('Build Episode URLs').item.json.episode_url + "\n\n" +
    "=== SHOW-PUBLISHED INSIGHTS (aidailybrief.ai) ===\n" + (($('Fetch Insights').item.json.body) || "(insights unavailable)") + "\n\n" +
    "=== FULL TRANSCRIPT ===\n" + (($('Fetch Transcript').item.json.body) || "")
  }]
}) }}

parameters.jsCode:
const DB = "640bfa89-154f-46fb-9ab9-ed198562f684";
const d = $input.first().json;
const tb = (d.content || []).find(b => b && b.type === "text");
let raw = (tb && tb.text) ? tb.text : "{}";
raw = raw.replace(/^```json\s*/i, "").replace(/```\s*$/, "").trim();
let p; try { p = JSON.parse(raw); } catch (e) { p = { episode_title: "AI Daily Brief — parse failed", episode_summary: "", idea: {} }; }
const idea = p.idea || {};
const urls = $('Build Episode URLs').item.json;
const insights = ($('Fetch Insights').item.json.body) || "";
const title = (p.episode_title && String(p.episode_title).trim()) ? ("AI Daily Brief — " + p.episode_title) : ("AI Daily Brief — " + urls.episode_date);
const chunks = [];
for (let i = 0; i < insights.length; i += 1900) chunks.push(insights.substring(i, i + 1900));
const insightBlocks = chunks.slice(0, 40).map(c => ({ object: "block", type: "paragraph", paragraph: { rich_text: [{ type: "text", text: { content: c } }] } }));
const source_body = {
  parent: { database_id: DB },
  properties: {
    Title: { title: [{ text: { content: title.substring(0, 200) } }] },
    Type: { select: { name: "Source" } },
    "Source Type": { select: { name: "podcast" } },
    Episode: { rich_text: [{ type: "text", text: { content: title.substring(0, 2000), link: { url: urls.episode_url } } }] },
    Published: { date: { start: urls.episode_date } },
    "Transcript Source": { select: { name: "AIDB Published" } },
    Topics: { multi_select: [{ name: "AI Strategy" }] }
  },
  children: [
    { object: "block", type: "heading_2", heading_2: { rich_text: [{ type: "text", text: { content: "Episode Insights (show-published)" } }] } },
    ...(insightBlocks.length ? insightBlocks : [{ object: "block", type: "paragraph", paragraph: { rich_text: [{ type: "text", text: { content: "(insights unavailable)" } }] } }]),
    { object: "block", type: "paragraph", paragraph: { rich_text: [{ type: "text", text: { content: "Full transcript: " + urls.transcript_url, link: { url: urls.transcript_url } } }] } }
  ]
};
return [{ json: { source_body, idea, episode_title: title, episode_summary: p.episode_summary || "", episode_date: urls.episode_date, episode_url: urls.episode_url } }];

const DB = "640bfa89-154f-46fb-9ab9-ed198562f684";
const src = $input.first().json;
const sourceId = (src && src.id) ? src.id : "";
const bb = $('Build Notion Bodies').item.json;
const idea = bb.idea || {};
const VALID = new Set(["Claude","Agents","AI Governance","Marketing AI","Measurement","AI Strategy","LLMs","MCP","Voice AI","AI Safety","Enterprise AI","Creator Economy","Policy","Research","Content","Prompt Engineering","Reddit/Search","OpenAI","Anthropic","Google","Meta","Codex"]);
const CANON = {"gemini":"Google","google":"Google","chatgpt":"OpenAI","gpt":"OpenAI","openai":"OpenAI","anthropic":"Anthropic","claude":"Claude","llama":"Meta","meta":"Meta","agent":"Agents","agentic":"Agents","governance":"AI Governance","responsible ai":"AI Governance","ethic":"AI Governance","safety":"AI Safety","alignment":"AI Safety","policy":"Policy","regulat":"Policy","marketing":"Marketing AI","advertis":"Marketing AI","measurement":"Measurement","attribution":"Measurement","analytics":"Measurement","strategy":"AI Strategy","llm":"LLMs","language model":"LLMs","mcp":"MCP","voice":"Voice AI","enterprise":"Enterprise AI","creator":"Creator Economy","research":"Research","paper":"Research","content":"Content","prompt":"Prompt Engineering","search":"Reddit/Search","reddit":"Reddit/Search","codex":"Codex"};
const normTopics = (ts) => { const out = new Set(); for (const t of (ts || [])) { const k = String(t || "").trim(); if (!k) continue; if (VALID.has(k)) { out.add(k); continue; } const lc = k.toLowerCase(); for (const [a, c] of Object.entries(CANON)) { if (lc.includes(a)) { out.add(c); break; } } } return out.size ? Array.from(out) : ["AI Strategy"]; };
const arr = v => Array.isArray(v) ? v : (v ? [v] : []);
const kp = arr(idea.key_points), obs = arr(idea.observations), tips = arr(idea.tips), quotes = arr(idea.quotes), fr = arr(idea.further_reading);
const children = [
  { object: "block", type: "heading_2", heading_2: { rich_text: [{ type: "text", text: { content: "Hook" } }] } },
  { object: "block", type: "paragraph", paragraph: { rich_text: [{ type: "text", text: { content: (idea.hook || "").substring(0, 2000) } }] } },
  { object: "block", type: "heading_2", heading_2: { rich_text: [{ type: "text", text: { content: "Key Threads" } }] } },
  ...kp.map(x => ({ object: "block", type: "bulleted_list_item", bulleted_list_item: { rich_text: [{ type: "text", text: { content: String(x).substring(0, 2000) } }] } })),
  ...(obs.length ? [{ object: "block", type: "heading_2", heading_2: { rich_text: [{ type: "text", text: { content: "Observations" } }] } }, ...obs.map(x => ({ object: "block", type: "bulleted_list_item", bulleted_list_item: { rich_text: [{ type: "text", text: { content: String(x).substring(0, 2000) } }] } }))] : []),
  ...(tips.length ? [{ object: "block", type: "heading_2", heading_2: { rich_text: [{ type: "text", text: { content: "Tips" } }] } }, ...tips.map(x => ({ object: "block", type: "bulleted_list_item", bulleted_list_item: { rich_text: [{ type: "text", text: { content: String(x).substring(0, 2000) } }] } }))] : []),
  ...(quotes.length ? [{ object: "block", type: "heading_2", heading_2: { rich_text: [{ type: "text", text: { content: "Quotes" } }] } }, ...quotes.map(q => ({ object: "block", type: "quote", quote: { rich_text: [{ type: "text", text: { content: ('"' + (q.quote || "") + '" — ' + (q.speaker || "Unknown") + (q.timestamp ? " (" + q.timestamp + ")" : "")).substring(0, 2000) } }] } }))] : []),
  { object: "block", type: "heading_2", heading_2: { rich_text: [{ type: "text", text: { content: "Why It Matters" } }] } },
  { object: "block", type: "paragraph", paragraph: { rich_text: [{ type: "text", text: { content: (idea.why_it_matters || "").substring(0, 2000) } }] } },
  { object: "block", type: "heading_2", heading_2: { rich_text: [{ type: "text", text: { content: "Draft Angle (whole-episode spine)" } }] } },
  { object: "block", type: "callout", callout: { icon: { type: "emoji", emoji: "💡" }, rich_text: [{ type: "text", text: { content: (idea.draft_angle || "").substring(0, 2000) } }] } },
  ...(idea.open_question ? [{ object: "block", type: "heading_2", heading_2: { rich_text: [{ type: "text", text: { content: "Open Question" } }] } }, { object: "block", type: "paragraph", paragraph: { rich_text: [{ type: "text", text: { content: String(idea.open_question).substring(0, 2000) } }] } }] : []),
  ...(fr.length ? [{ object: "block", type: "heading_2", heading_2: { rich_text: [{ type: "text", text: { content: "Further Reading" } }] } }, ...fr.map(r => ({ object: "block", type: "bulleted_list_item", bulleted_list_item: { rich_text: [{ type: "text", text: { content: (r.title || r.url || "").substring(0, 2000), link: r.url ? { url: r.url } : null } }] } }))] : []),
  { object: "block", type: "divider", divider: {} },
  { object: "block", type: "paragraph", paragraph: { rich_text: [{ type: "text", text: { content: ("Source: " + bb.episode_title + " [" + bb.episode_url + "] | whole-episode synthesis | model: Sonnet 5").substring(0, 2000) } }] } }
];
const idea_body = {
  parent: { database_id: DB },
  properties: {
    Title: { title: [{ text: { content: (idea.topic_headline || bb.episode_title || "AI Daily Brief").substring(0, 200) } }] },
    Type: { select: { name: "Idea" } },
    "Source Type": { select: { name: "podcast" } },
    Episode: { rich_text: [{ type: "text", text: { content: (bb.episode_title || "").substring(0, 2000), link: { url: bb.episode_url } } }] },
    Published: { date: { start: bb.episode_date } },
    "Hot Take Potential": { select: { name: idea.hot_take_potential || "Medium" } },
    Utility: { select: { name: idea.utility || "Medium" } },
    Relevance: { select: { name: idea.relevance || "High" } },
    Format: { select: { name: idea.format || "Explainer" } },
    Topics: { multi_select: normTopics(idea.topics).map(t => ({ name: t })) },
    Audience: { multi_select: (idea.audience || []).map(a => ({ name: String(a).substring(0, 90) })) },
    Summary: { rich_text: [{ text: { content: (idea.hook || bb.episode_summary || "").substring(0, 2000) } }] },
    "Extraction Model": { select: { name: "Sonnet 5" } },
    "Transcript Source": { select: { name: "AIDB Published" } },
    "Episode Source": sourceId ? { relation: [{ id: sourceId }] } : { relation: [] }
  },
  children
};
return [{ json: { idea_body } }];
